                        .as_ref()
                        .map(|emb| cosine_similarity(&embedding, emb))
                        .unwrap_or(0.0);
                    let blended = ((1.0 - self.alpha) * cosine + self.alpha * (0.5 * 0.67))
                        * tier_weight(entry.tier);
